diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 275b3d567856..d20988239736 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7374,7 +7374,33 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
     return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop, BB](Instruction &I) {
       if (isa<PHINode>(&I) && BB == TheLoop->getHeader())
         return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
+      
+      // If the instruction is missing from the VPlan, check if it represents
+      // a uniform operation that can be optimized away in VPlan.
+      if (!SeenInstrs.contains(&I)) {
+        // For load instructions, check if the pointer operand is loop-invariant
+        if (auto *LI = dyn_cast<LoadInst>(&I)) {
+          if (TheLoop->isLoopInvariant(LI->getPointerOperand()))
+            return true;
+        }
+        // For other instructions, check if all operands are loop-invariant
+        // (making the instruction itself uniform)
+        else if (!isa<StoreInst>(&I)) {
+          bool AllOperandsInvariant = true;
+          for (Value *Op : I.operands()) {
+            if (!TheLoop->isLoopInvariant(Op)) {
+              AllOperandsInvariant = false;
+              break;
+            }
+          }
+          if (AllOperandsInvariant)
+            return true;
+        }
+        
+        if (!CostCtx.skipCostComputation(&I, true))
+          return true;
+      }
+      return false;
     });
   });
 }
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 275b3d567856..67e1b1ebdf68 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7369,12 +7369,32 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
+  // 
+  // We need to be more permissive about instructions that might be optimized
+  // away in the VPlan but still exist in the original loop. In particular,
+  // uniform loads (loads with loop-invariant addresses) and their dependent
+  // computations can be hoisted and simplified in the VPlan.
   return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx,
                                     TheLoop](BasicBlock *BB) {
     return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop, BB](Instruction &I) {
       if (isa<PHINode>(&I) && BB == TheLoop->getHeader())
         return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
+      
+      // If the instruction is not in the VPlan, check if it should be considered
+      // as an additional simplification.
+      if (!SeenInstrs.contains(&I)) {
+        // Check if this is a uniform load (loop-invariant address)
+        if (auto *LI = dyn_cast<LoadInst>(&I)) {
+          if (TheLoop->isLoopInvariant(LI->getPointerOperand()))
+            return true;
+        }
+        
+        // If the instruction is not marked to be skipped in cost computation,
+        // then its absence from the VPlan represents an additional simplification.
+        if (!CostCtx.skipCostComputation(&I, true))
+          return true;
+      }
+      return false;
     });
   });
 }
